#!/usr/bin/env python3
"""Dream Abroad v11.1 - Fix: Edicao de usuarios nas Configuracoes"""
import base64, os, sys

BASE = os.path.expanduser("~/Desktop/dream-abroad")

files = {
    "backend/main.py": "",
    "backend/schemas.py": "",
    "backend/routers/auth_router.py": "",
    "backend/routers/alerts.py": "",
    "backend/routers/payments.py": "",
    "backend/routers/documents.py": "",
    "backend/routers/clients.py": "",
    "backend/routers/rooms.py": "",
    "backend/routers/contracts.py": "",
    "frontend/src/App.tsx": "",
    "frontend/src/components/Layout.tsx": "",
    "frontend/src/components/FileUpload.tsx": "",
    "frontend/src/contexts/AuthContext.tsx": "",
    "frontend/src/pages/Dashboard.tsx": "",
    "frontend/src/pages/Alerts.tsx": "",
    "frontend/src/pages/PaymentTracking.tsx": "",
    "frontend/src/pages/Properties.tsx": "",
    "frontend/src/pages/PropertyProfile.tsx": "",
    "frontend/src/pages/ClientProfile.tsx": "",
    "frontend/src/pages/Clients.tsx": "",
    "frontend/src/pages/Contracts.tsx": "",
    "frontend/src/pages/Availability.tsx": "",
    "frontend/src/pages/UserProfile.tsx": "",
    "frontend/src/pages/SettingsPage.tsx": "",
    "frontend/src/services/api.ts": "",
    "frontend/vite.config.ts": "",
}

def main():
    if not os.path.isdir(BASE):
        print(f"ERROR: {BASE} nao encontrado"); sys.exit(1)
    print("Aplicando Dream Abroad v11.1...")
    print()
    for rel, b64 in files.items():
        path = os.path.join(BASE, rel)
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "wb") as f:
            f.write(base64.b64decode(b64))
        print(f"  OK {rel}")
    uploads_dir = os.path.join(BASE, "backend", "uploads")
    os.makedirs(uploads_dir, exist_ok=True)
    print()
    print("v11.1 aplicado com sucesso!")

if __name__ == "__main__":
    main()